<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu Web Desktop</title>
    <style>
        :root {
            --ubuntu-purple: #300a24;
            --ubuntu-darker: #2c0820;
            --taskbar-bg: rgba(0, 0, 0, 0.7);
            --win-bg: #f2f1f0;
            --win-header: #e0e0e0;
            --text-main: #333;
            --accent: #E95420;
        }

        * { box-sizing: border-box; }
        body, html { 
            margin: 0; padding: 0; 
            width: 100%; height: 100%; 
            font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            overflow: hidden;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: var(--ubuntu-purple);
            background: linear-gradient(135deg, #5E2750 0%, #2C0820 100%);
            position: relative;
            overflow: hidden;
        }

        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            height: 50px;
            background: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            border-radius: 12px;
            display: flex;
            align-items: center;
            padding: 0 15px;
            gap: 15px;
            z-index: 9999;
            border: 1px solid rgba(255,255,255,0.1);
        }

        .launcher {
            width: 36px;
            height: 36px;
            border-radius: 8px;
            border: none;
            cursor: pointer;
            background: #fff;
            font-size: 20px;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: transform 0.1s, background 0.2s;
        }
        .launcher:hover { background: #ddd; transform: scale(1.1); }
        .launcher:active { transform: scale(0.9); }

        /* Window Styles */
        .window {
            position: absolute;
            width: 450px;
            height: 320px;
            min-width: 360px;
            min-height: 240px;
            background: var(--win-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none;
            flex-direction: column;
            overflow: hidden;
            z-index: 10;
        }

        .win-header {
            height: 35px;
            background: var(--win-header);
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            cursor: move;
            user-select: none;
            border-bottom: 1px solid #ccc;
        }

        .win-title { font-size: 13px; font-weight: bold; color: #555; }

        .win-close {
            width: 24px;
            height: 24px;
            border-radius: 50%;
            border: none;
            background: transparent;
            cursor: pointer;
            font-weight: bold;
            color: #888;
        }
        .win-close:hover { background: #ff5f56; color: white; }

        .win-content {
            flex: 1;
            position: relative;
            overflow: auto;
            background: white;
        }

        /* Files App Styles */
        #files-toolbar {
            display: flex;
            gap: 5px;
            padding: 8px;
            background: #eee;
            border-bottom: 1px solid #ddd;
            align-items: center;
        }
        #files-path {
            flex: 1;
            padding: 4px 8px;
            border: 1px solid #ccc;
            font-family: monospace;
            font-size: 12px;
        }
        #files-up {
            padding: 4px 8px;
            cursor: pointer;
            background: #ddd;
            border: 1px solid #bbb;
            font-size: 12px;
        }

        .fs-list {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
            padding: 20px;
        }
        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            text-align: center;
            cursor: pointer;
            font-size: 12px;
            padding: 5px;
            border-radius: 4px;
            user-select: none;
        }
        .fs-item:hover { background: #e8f0fe; }
        .fs-icon { font-size: 32px; margin-bottom: 5px; }

        /* Notepad App Styles */
        #notepad-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }
        #tabs {
            display: flex;
            background: #ddd;
            overflow-x: auto;
            border-bottom: 1px solid #bbb;
        }
        .tab {
            padding: 8px 15px;
            cursor: pointer;
            font-size: 12px;
            background: #ccc;
            border-right: 1px solid #bbb;
            white-space: nowrap;
            user-select: none;
        }
        .tab.active { background: white; font-weight: bold; }
        #new-tab {
            padding: 8px 12px;
            cursor: pointer;
            background: #ddd;
            border: none;
            font-weight: bold;
            font-size: 16px;
        }
        #editor {
            flex: 1;
            width: 100%;
            height: 100%;
            border: none;
            padding: 10px;
            resize: none;
            font-family: 'Consolas', 'Monaco', monospace;
            outline: none;
        }
    </style>
</head>
<body>

<div id="desktop">
    <div id="taskbar">
        <button id="open-files" class="launcher" title="Files">📁</button>
        <button id="open-notepad" class="launcher" title="Notepad">📝</button>
    </div>

    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="win-header">
            <span class="win-title">Files</span>
            <button class="win-close">&times;</button>
        </div>
        <div class="win-content">
            <div id="files-toolbar">
                <button id="files-up">UP</button>
                <input type="text" id="files-path" readonly>
            </div>
            <div id="fs-container" class="fs-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="win-header">
            <span class="win-title">Notepad</span>
            <button class="win-close">&times;</button>
        </div>
        <div class="win-content">
            <div id="notepad-container">
                <div id="tabs"></div>
                <button id="new-tab">+</button>
                <textarea id="editor"></textarea>
            </div>
        </div>
    </div>
</div>

<script>
    /** WINDOW MANAGEMENT **/
    function makeDraggable(win) {
        const header = win.querySelector('.win-header');
        let pos1 = 0, pos2 = 0, pos3 = 0, pos4 = 0;
        header.onmousedown = dragMouseDown;

        function dragMouseDown(e) {
            e.preventDefault();
            pos3 = e.clientX;
            pos4 = e.clientY;
            document.onmouseup = closeDragElement;
            document.onmousemove = elementDrag;
            // Bring to front
            document.querySelectorAll('.window').forEach(w => w.style.zIndex = 10);
            win.style.zIndex = 100;
        }

        function elementDrag(e) {
            e.preventDefault();
            pos1 = pos3 - e.clientX;
            pos2 = pos4 - e.clientY;
            pos3 = e.clientX;
            pos4 = e.clientY;
            win.style.top = (win.offsetTop - pos2) + "px";
            win.style.left = (win.offsetLeft - pos1) + "px";
        }

        function closeDragElement() {
            document.onmouseup = null;
            document.onmousemove = null;
        }
    }

    const filesWin = document.getElementById('files-window');
    const notepadWin = document.getElementById('notepad-window');
    makeDraggable(filesWin);
    makeDraggable(notepadWin);

    document.getElementById('open-files').onclick = () => { 
        filesWin.style.display = 'flex'; 
        filesWin.style.top = '50px'; filesWin.style.left = '50px';
    };
    document.getElementById('open-notepad').onclick = () => { 
        notepadWin.style.display = 'flex'; 
        notepadWin.style.top = '100px'; notepadWin.style.left = '100px';
    };

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.onclick = (e) => { e.target.closest('.window').style.display = 'none'; };
    });

    /** FILES APP LOGIC **/
    const filesystem = {
        '/': { type: 'dir', children: ['bin', 'etc', 'home', 'usr', 'var'] },
        '/bin': { type: 'dir', children: ['bash', 'ls', 'mkdir', 'rm'] },
        '/etc': { type: 'dir', children: ['hosts', 'passwd', 'resolv.conf'] },
        '/home': { type: 'dir', children: ['user'] },
        '/home/user': { type: 'dir', children: ['Documents', 'Downloads', 'Pictures', 'todo.txt', 'readme.md'] },
        '/home/user/Documents': { type: 'dir', children: ['resume.pdf', 'budget.xlsx'] },
        '/home/user/Downloads': { type: 'dir', children: ['ubuntu-installer.iso', 'wallpaper.jpg'] },
        '/home/user/Pictures': { type: 'dir', children: ['vacation.png', 'profile.jpg'] },
        '/usr': { type: 'dir', children: ['bin', 'lib', 'share'] },
        '/var': { type: 'dir', children: ['log', 'mail', 'tmp'] },
    };

    let currentPath = '/';

    function renderFiles() {
        const container = document.getElementById('fs-container');
        const pathDisplay = document.getElementById('files-path');
        pathDisplay.value = currentPath;
        container.innerHTML = '';

        const folder = filesystem[currentPath];
        if (folder && folder.children) {
            folder.children.forEach(name => {
                const fullPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
                const isDir = !!filesystem[fullPath];

                const item = document.createElement('div');
                item.className = 'fs-item';
                item.innerHTML = `<div class="fs-icon">${isDir ? '📁' : '📄'}</div><div>${name}</div>`;

                item.ondblclick = () => {
                    if (isDir) {
                        currentPath = fullPath;
                        renderFiles();
                    }
                };
                container.appendChild(item);
            });
        }
    }

    document.getElementById('files-up').onclick = () => {
        if (currentPath === '/') return;
        const parts = currentPath.split('/').filter(Boolean);
        parts.pop();
        currentPath = '/' + parts.join('/');
        if (currentPath === '') currentPath = '/';
        renderFiles();
    };

    renderFiles();

    /** NOTEPAD APP LOGIC **/
    const editor = document.getElementById('editor');
    const tabsContainer = document.getElementById('tabs');
    let notepadData = {
        tabs: [{ id: Date.now(), title: 'Untitled 1', content: '' }],
        activeTabId: null
    };

    function loadNotepad() {
        const saved = localStorage.getItem('ubuntu_notepad_data');
        if (saved) {
            notepadData = JSON.parse(saved);
        } else {
            notepadData.activeTabId = notepadData.tabs[0].id;
        }
        renderTabs();
        switchTab(notepadData.activeTabId);
    }

    function saveNotepad() {
        localStorage.setItem('ubuntu_notepad_data', JSON.stringify(notepadData));
    }

    function renderTabs() {
        tabsContainer.innerHTML = '';
        notepadData.tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = `tab ${tab.id === notepadData.activeTabId ? 'active' : ''}`;
            tabEl.textContent = tab.title;
            tabEl.onclick = () => switchTab(tab.id);
            tabsContainer.appendChild(tabEl);
        });
    }

    function switchTab(id) {
        notepadData.activeTabId = id;
        const activeTab = notepadData.tabs.find(t => t.id === id);
        editor.value = activeTab ? activeTab.content : '';
        renderTabs();
    }

    document.getElementById('new-tab').onclick = () => {
        const newId = Date.now();
        notepadData.tabs.push({ 
            id: newId, 
            title: `Untitled ${notepadData.tabs.length + 1}`, 
            content: '' 
        });
        switchTab(newId);
        saveNotepad();
    };

    editor.oninput = () => {
        const activeTab = notepadData.tabs.find(t => t.id === notepadData.activeTabId);
        if (activeTab) {
            activeTab.content = editor.value;
            saveNotepad();
        }
    };

    loadNotepad();
</script>

</body>
</html>
